-- usp_CloseRunLog: stamps final status, counts, and end time on the run log
CREATE   PROCEDURE control.usp_CloseRunLog
    @RUN_ID               UNIQUEIDENTIFIER,
    @END_EXECUTION_ID     INT,
    @STEPS_SUCCESS        INT,
    @STEPS_FAILED         INT,
    @STEPS_SKIPPED        INT,
    @RUN_STATUS           VARCHAR(20),        -- 'SUCCESS' | 'FAILED' | 'HALTED'
    @HALT_AT_EXECUTION_ID INT = NULL
AS
BEGIN
    SET NOCOUNT ON;
    UPDATE control.EXECUTION_RUN_LOG SET
        RUN_END_DATETIME     = SYSUTCDATETIME(),
        END_EXECUTION_ID     = @END_EXECUTION_ID,
        STEPS_SUCCESS        = @STEPS_SUCCESS,
        STEPS_FAILED         = @STEPS_FAILED,
        STEPS_SKIPPED        = @STEPS_SKIPPED,
        TOTAL_STEPS          = @STEPS_SUCCESS + @STEPS_FAILED + @STEPS_SKIPPED,
        RUN_STATUS           = @RUN_STATUS,
        HALT_AT_EXECUTION_ID = @HALT_AT_EXECUTION_ID
    WHERE RUN_ID = @RUN_ID;
END;

-- usp_CloseStepLog: stamps end time, status, and optional error on the most
-- recent open row for this RUN_ID + EXECUTION_ID + ATTEMPT_NUMBER combination.
CREATE   PROCEDURE control.usp_CloseStepLog
    @RUN_ID         UNIQUEIDENTIFIER,
    @EXECUTION_ID   INT,
    @ATTEMPT_NUMBER TINYINT,
    @STATUS         VARCHAR(20),   -- 'SUCCESS' | 'FAILED' | 'SKIPPED'
    @ROW_COUNT      BIGINT       = NULL,
    @ERROR_MESSAGE  VARCHAR(MAX) = NULL,
    @ERROR_CODE     VARCHAR(50)  = NULL
AS
BEGIN
    SET NOCOUNT ON;
    UPDATE control.EXECUTION_STEP_LOG SET
        END_DATETIME  = SYSUTCDATETIME(),
        STATUS        = @STATUS,
        ROW_COUNT     = @ROW_COUNT,
        ERROR_MESSAGE = @ERROR_MESSAGE,
        ERROR_CODE    = @ERROR_CODE
    WHERE RUN_ID        = @RUN_ID
      AND EXECUTION_ID  = @EXECUTION_ID
      AND ATTEMPT_NUMBER= @ATTEMPT_NUMBER
      AND STATUS IN ('RUNNING', 'RETRYING', 'SKIPPED');
END;

-- ── Helper Stored Procedures ─────────────────────────────────────────────────
-- These are called by Fabric pipeline Script activities.
-- Parameters are deliberately minimal to reduce expression complexity in pipelines.

-- usp_OpenRunLog: creates the run log entry at pipeline start
CREATE   PROCEDURE control.usp_OpenRunLog
    @RUN_ID               UNIQUEIDENTIFIER,
    @START_EXECUTION_ID   INT,
    @TRIGGERED_BY         VARCHAR(100),
    @SEND_EMAIL           BIT,
    @EMAIL_RECIPIENTS     VARCHAR(1000)
AS
BEGIN
    SET NOCOUNT ON;
    INSERT INTO control.EXECUTION_RUN_LOG
        (RUN_ID, RUN_START_DATETIME, START_EXECUTION_ID,
         RUN_STATUS, TRIGGERED_BY, SEND_EMAIL, EMAIL_RECIPIENTS)
    VALUES
        (@RUN_ID, SYSUTCDATETIME(), @START_EXECUTION_ID,
         'RUNNING', @TRIGGERED_BY, @SEND_EMAIL, @EMAIL_RECIPIENTS);
END;

CREATE PROCEDURE control.usp_OpenStepLog
    @RUN_ID         UNIQUEIDENTIFIER,
    @EXECUTION_ID   INT,
    @ATTEMPT_NUMBER TINYINT,
    @STATUS         VARCHAR(20)
AS
BEGIN
    SET NOCOUNT ON;
    INSERT INTO control.EXECUTION_STEP_LOG
        (RUN_ID, EXECUTION_ID, STEP_NAME, STEP_TYPE,
         EXECUTION_DATABASE, OBJECT_NAME, IS_ACTIVE,
         ATTEMPT_NUMBER, START_DATETIME, STATUS)
    SELECT
        @RUN_ID, @EXECUTION_ID, STEP_NAME, STEP_TYPE,
        STEP_DATABASE, TARGET_OBJECT, FLAG_ACTIVE,
        @ATTEMPT_NUMBER, SYSUTCDATETIME(), @STATUS
    FROM control.EXECUTION_PLAN
    WHERE EXECUTION_ID = @EXECUTION_ID;
END

-- usp_UpdatePlanLastRun: stamps LAST_RUN_* columns on EXECUTION_PLAN after each step.
CREATE   PROCEDURE control.usp_UpdatePlanLastRun
    @RUN_ID        UNIQUEIDENTIFIER,
    @EXECUTION_ID  INT,
    @STATUS        VARCHAR(20),
    @DURATION_S    INT
AS
BEGIN
    SET NOCOUNT ON;
    UPDATE control.EXECUTION_PLAN SET
        LAST_RUN_ID         = @RUN_ID,
        LAST_RUN_DATETIME   = SYSUTCDATETIME(),
        LAST_RUN_STATUS     = @STATUS,
        LAST_RUN_DURATION_S = @DURATION_S
    WHERE EXECUTION_ID = @EXECUTION_ID;
END;

