AS
BEGIN
    SET NOCOUNT ON;

    DECLARE @StartTime DATETIME2(3) = SYSDATETIME();
    DECLARE @SourceRows INT = 0;
    DECLARE @TargetRows INT = 0;
    DECLARE @TodaysDateInt INT = CAST(CONVERT(VARCHAR(8), SYSDATETIME(), 112) AS INT);

    BEGIN TRY
        BEGIN TRANSACTION;

        -- ATL Strategy: Append (Keep history of checks). 
        -- However, for a daily check table, we often just want the latest status. 
        -- Based on ATL "Append", we will Insert.

        /*
         * ------------------------------------------------------------------------------------------------------------
         * TRANSFORMATION LOGIC
         * ------------------------------------------------------------------------------------------------------------
         */
        WITH [MaxFileDate] AS (
            -- Extract 1st 8 chars from filename (YYYYMMDD) and find the MAX
            SELECT 
                MAX(TRY_CAST(LEFT([DI_FILENAME], 8) AS INT)) AS [SOURCE_FILE_DATE]
            FROM [dbo].[STG_PAYCOM_DIRECTORY_LIST]
            WHERE ISNUMERIC(LEFT([DI_FILENAME], 8)) = 1 -- Safety check
        ),
        [DateCompare] AS (
            SELECT 
                @TodaysDateInt AS [DATE_KEY],
                [SOURCE_FILE_DATE],
                -- Logic: If Today = MaxFileDate, then 1, else 0
                CASE 
                    WHEN @TodaysDateInt = [SOURCE_FILE_DATE] THEN 1 
                    ELSE 0 
                END AS [SOURCE_FILE_CHECK]
            FROM [MaxFileDate]
        )
        INSERT INTO [dbo].[IMPORT_PAYCOM_FILECHECK] (
            [DATE_KEY],
            [SOURCE_FILE_DATE],
            [SOURCE_FILE_CHECK],
            [LAST_RUN_DT]
        )
        SELECT 
            [DATE_KEY],
            [SOURCE_FILE_DATE],
            [SOURCE_FILE_CHECK],
            SYSDATETIME()
        FROM [DateCompare];

        SET @TargetRows = @@ROWCOUNT;

        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
        THROW;
    END CATCH;

    -- Return Status
    SELECT 
        'Success' AS [Status],
        @TargetRows AS [Rows_Inserted],
        @TodaysDateInt AS [Checked_Against_Date],
        DATEDIFF(MILLISECOND, @StartTime, SYSDATETIME()) AS [Execution_Time_MS];
END;

