CREATE PROCEDURE [dbo].[MARKET_SURVEY_AGG_SP]
AS
BEGIN
    SET NOCOUNT ON;/* ---------------------------------------------------------
           1) Stage source rows (avoids hard-coded column references)
        --------------------------------------------------------- */
        IF OBJECT_ID('tempdb..#SRC') IS NOT NULL DROP TABLE #SRC;

        SELECT *
        INTO #SRC
        FROM [WH_STAGING].[dbo].[MARKET_SURVEY_AGG_F];

        /* ---------------------------------------------------------
           2) Impacted key set (DATE_KEY is required by ATL)
        --------------------------------------------------------- */
        IF OBJECT_ID('tempdb..#KEYS') IS NOT NULL DROP TABLE #KEYS;

        SELECT DISTINCT DATE_KEY
        INTO #KEYS
        FROM #SRC
        WHERE DATE_KEY IS NOT NULL;

        /* ---------------------------------------------------------
           3) Delete impacted rows in target
        --------------------------------------------------------- */
        DELETE T
        FROM [WH_PROD2].[dbo].[MARKET_SURVEY_AGG] AS T
        INNER JOIN #KEYS AS K
            ON K.DATE_KEY = T.DATE_KEY;

        /* ---------------------------------------------------------
           4) Build column intersection (no WITH / no CTE)
              Fix collation conflicts explicitly when comparing names.
        --------------------------------------------------------- */
        DECLARE @HasLastUpdated BIT = 0;

        SELECT @HasLastUpdated =
            CASE WHEN EXISTS (
                SELECT 1
                FROM [WH_PROD2].sys.columns c
                INNER JOIN [WH_PROD2].sys.objects o ON o.object_id = c.object_id
                INNER JOIN [WH_PROD2].sys.schemas s ON s.schema_id = o.schema_id
                WHERE s.name = 'dbo'
                  AND o.name = 'MARKET_SURVEY_AGG'
                  AND c.name = 'LASTUPDATED'
            ) THEN 1 ELSE 0 END;

        IF OBJECT_ID('tempdb..#SrcCols') IS NOT NULL DROP TABLE #SrcCols;
        IF OBJECT_ID('tempdb..#TgtCols') IS NOT NULL DROP TABLE #TgtCols;
        IF OBJECT_ID('tempdb..#CommonCols') IS NOT NULL DROP TABLE #CommonCols;

        CREATE TABLE #SrcCols (COLNAME SYSNAME NOT NULL);
        CREATE TABLE #TgtCols (COLNAME SYSNAME NOT NULL);
        CREATE TABLE #CommonCols (COLNAME SYSNAME NOT NULL);

        -- Source columns from #SRC temp table (tempdb)
        INSERT INTO #SrcCols (COLNAME)
        SELECT c.name
        FROM tempdb.sys.columns c
        INNER JOIN tempdb.sys.objects o ON o.object_id = c.object_id
        WHERE o.name LIKE '#SRC%';

        -- Target columns from PROD table (WH_PROD2)
        INSERT INTO #TgtCols (COLNAME)
        SELECT c.name
        FROM [WH_PROD2].sys.columns c
        INNER JOIN [WH_PROD2].sys.objects o ON o.object_id = c.object_id
        INNER JOIN [WH_PROD2].sys.schemas s ON s.schema_id = o.schema_id
        WHERE s.name = 'dbo'
          AND o.name = 'MARKET_SURVEY_AGG';

        -- Intersection (exclude LASTUPDATED from the common list; handled separately)
        INSERT INTO #CommonCols (COLNAME)
        SELECT T.COLNAME
        FROM #TgtCols AS T
        INNER JOIN #SrcCols AS S
            ON S.COLNAME COLLATE Latin1_General_100_BIN2_UTF8
             = T.COLNAME COLLATE Latin1_General_100_BIN2_UTF8
        WHERE T.COLNAME <> 'LASTUPDATED';

        DECLARE @InsertCols NVARCHAR(MAX);
        DECLARE @SelectCols NVARCHAR(MAX);

        SELECT
            @InsertCols = STRING_AGG(QUOTENAME(COLNAME), ','),
            @SelectCols = STRING_AGG('S.' + QUOTENAME(COLNAME), ',')
        FROM #CommonCols;

        IF @InsertCols IS NULL OR LTRIM(RTRIM(@InsertCols)) = ''
        BEGIN
            RAISERROR('No matching columns found between source [WH_STAGING].[dbo].[MARKET_SURVEY_AGG_F] and target [WH_PROD2].[dbo].[MARKET_SURVEY_AGG].', 16, 1);
        END

        /* ---------------------------------------------------------
           5) Insert refreshed rows (adds LASTUPDATED only if present)
        --------------------------------------------------------- */
        DECLARE @SQL NVARCHAR(MAX) =
            N'INSERT INTO [WH_PROD2].[dbo].[MARKET_SURVEY_AGG] (' +
                @InsertCols +
                CASE WHEN @HasLastUpdated = 1 THEN N', [LASTUPDATED]' ELSE N'' END +
            N') ' +
            N'SELECT ' +
                @SelectCols +
                CASE WHEN @HasLastUpdated = 1 THEN N', SYSDATETIME()' ELSE N'' END +
            N' FROM #SRC AS S;';

        EXEC sp_executesql @SQL;END;

-- 2. Create Wrapper (Standard)
CREATE PROCEDURE [dbo].[MIGRATION_WRAPPER_SILENT_SP]
    @ProcName       VARCHAR(255),
    @LogicType      VARCHAR(50),
    @TargetTable    VARCHAR(255),
    @BatchID        VARCHAR(50)
AS
BEGIN
    IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;

    DECLARE @Start DATETIME2(6) = SYSDATETIME();
    DECLARE @End   DATETIME2(6);
    DECLARE @Msg   VARCHAR(8000) = NULL;
    DECLARE @Stat  VARCHAR(50)   = 'SUCCESS';
    DECLARE @Cat   VARCHAR(50)   = 'NONE';
    DECLARE @Pre   BIGINT = NULL;
    DECLARE @Post  BIGINT = NULL;
    DECLARE @SQL   VARCHAR(1000);

    -- Pre-Check
    IF @TargetTable <> 'Unknown' AND LEFT(@TargetTable, 1) <> '#'
    BEGIN
        BEGIN TRY
            DECLARE @Q1 NVARCHAR(1000) = N'SELECT @c = COUNT(*) FROM ' + @TargetTable;
            EXEC sp_executesql @Q1, N'@c BIGINT OUTPUT', @c = @Pre OUTPUT;
        END TRY
        BEGIN CATCH SET @Pre = -1; END CATCH
    END

    -- Run
    BEGIN TRY
        SET @SQL = 'EXEC ' + @ProcName;
        EXEC(@SQL);
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
        SET @Stat = 'FAILED';
        SET @Msg  = CAST(ERROR_MESSAGE() AS VARCHAR(8000));
        SET @Cat = CASE 
            WHEN @Msg LIKE '%Invalid object name%' THEN 'MISSING_DEPENDENCY'
            WHEN @Msg LIKE '%Reference to database%' THEN '3_PART_NAMING'
            WHEN @Msg LIKE '%syntax%' THEN 'SYNTAX_ERROR'
            ELSE 'GENERIC_FAILURE'
        END;
    END CATCH

    IF @Stat = 'SUCCESS' AND @@TRANCOUNT > 0
    BEGIN
        ROLLBACK TRANSACTION;
        SET @Cat = 'WARNING_OPEN_TRAN';
    END

    -- Post-Check
    IF @Stat = 'SUCCESS' AND @TargetTable <> 'Unknown' AND LEFT(@TargetTable, 1) <> '#'
    BEGIN
        BEGIN TRY
            DECLARE @Q2 NVARCHAR(1000) = N'SELECT @c = COUNT(*) FROM ' + @TargetTable;
            EXEC sp_executesql @Q2, N'@c BIGINT OUTPUT', @c = @Post OUTPUT;
        END TRY
        BEGIN CATCH SET @Post = -1; END CATCH
    END

    SET @End = SYSDATETIME();

    INSERT INTO dbo.Migration_Log (
        BatchID, ProcName, LogicType, TargetTableHint, Status, ErrorMessage, ErrorCategory,
        PreRowCount, PostRowCount, RowsAffected, StartTime, EndTime, DurationSec
    )
    VALUES (
        @BatchID, @ProcName, @LogicType, @TargetTable, @Stat, @Msg, @Cat,
        @Pre, @Post, (ISNULL(@Post,0) - ISNULL(@Pre,0)), @Start, @End, DATEDIFF(SECOND, @Start, @End)
    );
END;

