CREATE   PROCEDURE [dbo].[PROPERTY_GROUP_F_SYNC_SP]
AS
BEGIN
    SET NOCOUNT ON;
    BEGIN TRY
        BEGIN TRANSACTION;

        -- Truncate the target table
        TRUNCATE TABLE [WH_STAGING].[dbo].[PROPERTY_GROUP_F];

        -- Using CTE for Source Transformation (Mapped from ATL View: Query)
        WITH [CTE_Query] AS (
            SELECT 
                [PROPERTY_GROUP_KEY],
                [PROPERTY_GROUP_NAME],
                [FLAG_ACTIVE]
            FROM [DB_APP_SUPPORT].[dbo].[PROPERTY_GROUP_0]
        )
        INSERT INTO [WH_STAGING].[dbo].[PROPERTY_GROUP_F] (
            [PROPERTY_GROUP_KEY],
            [PROPERTY_GROUP_NAME],
            [FLAG_ACTIVE]
        )
        SELECT 
            [PROPERTY_GROUP_KEY],
            [PROPERTY_GROUP_NAME],
            [FLAG_ACTIVE]
        FROM [CTE_Query];

        COMMIT TRANSACTION;
    END TRY
    BEGIN CATCH
        IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;
        -- Use THROW for modern Fabric error handling
        DECLARE @Msg NVARCHAR(4000) = ERROR_MESSAGE();
        THROW 50000, @Msg, 1;
    END CATCH
END;

CREATE PROCEDURE [dbo].[REPORT_DICTIONARY_SP]
AS
BEGIN
    -- Resilience: Rollback any outer transaction if it exists
    IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;

    BEGIN TRY
        BEGIN TRANSACTION;

        -- Load Strategy: Full Reload
        TRUNCATE TABLE [WH_PROD2].[dbo].[REPORT_DICTIONARY];

        -- Transformation Logic
        INSERT INTO [WH_PROD2].[dbo].[REPORT_DICTIONARY] (
            [DICTIONARY_KEY], 
            [TYPE], 
            [ELEMENT], 
            [FAQ], 
            [DEFINITION], 
            [LAST_RUN_DT]
        )
        SELECT 
            ISNULL(Dictionary_KEY, -1),
            CAST([Type] AS VARCHAR(1000)),
            CAST([Element] AS VARCHAR(1000)),
            CAST([FAQ] AS VARCHAR(1000)),
            CAST([Definition] AS VARCHAR(1000)),
            SYSDATETIME()
        FROM [WH_STAGING].[dbo].[Report_Dictionary_0]; 

        COMMIT TRANSACTION;
        PRINT 'SUCCESS: [REPORT_DICTIONARY_SP] executed successfully.';
    END TRY
    BEGIN CATCH
        -- Clean up transaction count
        IF @@TRANCOUNT > 0 ROLLBACK TRANSACTION;

        DECLARE @ErrorMessage NVARCHAR(4000) = ERROR_MESSAGE();
        PRINT 'FAILURE: ' + @ErrorMessage;
        THROW;
    END CATCH
END;

